function LFightPbParser:ParsePb(msgid,bytes,callback)
    local pb = LProtoHelper.CreateProto(msgid)
    if not pb then
        LogError("decode pb can't find | " .. msgid)
        return
    end

    self:Clear()

    local fieldNameMap =
    {
        ["rounds"] = true
    }

    local pos,isEnd,fieldParser

    local parseFunc = function()
        pos,isEnd,fieldParser = pb:FrameParseString(bytes,pos,fieldParser,fieldNameMap)

        if not isEnd then
            return
        end
        self:Clear()

        if callback then
            callback(pb)
        end
    end

    self._timer = LFrameTimer.New(parseFunc, 1, -1)
    self._timer:Start()
end

function LFightPbParser:Destroy()
